const TZ = 'Atlantic/Canary';

// ================================
// 1) Normalización de entrada
// ================================
const horarios = items.map(i => {
  const j = i.json || {};
  return {
    dia: j.dia ?? j.Dia ?? j.day_name ?? j.dayName ?? null,
    disponible: j.disponible ?? j.Disponible ?? j.is_open ?? j.isOpen ?? null,
    apertura1: j.apertura_1 ?? j.Apertura1 ?? j.open_time_1 ?? j.openTime1 ?? null,
    cierre1: j.cierre_1 ?? j.Cierre1 ?? j.close_time_1 ?? j.closeTime1 ?? null,
    apertura2: j.apertura_2 ?? j.Apertura2 ?? j.open_time_2 ?? j.openTime2 ?? null,
    cierre2: j.cierre_2 ?? j.Cierre2 ?? j.close_time_2 ?? j.closeTime2 ?? null,
  };
});

const diasSemana = [
  'domingo',
  'lunes',
  'martes',
  'miercoles',
  'jueves',
  'viernes',
  'sabado',
];

// ================================
// 2) Helpers
// ================================
function normalizar(texto) {
  if (texto === null || texto === undefined) return '';
  return texto
    .toString()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .trim()
    .toLowerCase();
}

function capitalizar(texto) {
  if (!texto) return '';
  return texto.charAt(0).toUpperCase() + texto.slice(1);
}

function formatearHora(hora) {
  if (!hora) return null;
  const partes = hora.toString().split(':');
  if (partes.length < 2) return hora.toString();
  return `${partes[0].padStart(2, '0')}:${partes[1].padStart(2, '0')}`;
}

function toMinutes(hora) {
  if (!hora) return null;
  const partes = hora.toString().split(':');
  if (partes.length < 2) return null;

  const h = Number(partes[0]);
  const m = Number(partes[1]);

  if (Number.isNaN(h) || Number.isNaN(m)) return null;
  return h * 60 + m;
}

function valorBooleano(v) {
  if (typeof v === 'boolean') return v;
  const t = normalizar(v);
  return ['si', 'sí', 'true', '1', 'abierto', 'open'].includes(t);
}

function buscarDia(dia) {
  return horarios.find(h => normalizar(h.dia) === normalizar(dia));
}

function estaDisponible(config) {
  return !!config && valorBooleano(config.disponible);
}

function intervaloCruzaMedianoche(aperturaMin, cierreMin) {
  return aperturaMin !== null && cierreMin !== null && aperturaMin > cierreMin;
}

function estaDentroDelIntervalo(horaActualMin, aperturaMin, cierreMin) {
  if (aperturaMin === null || cierreMin === null) return false;

  // Caso normal: 12:00 - 15:30
  if (aperturaMin <= cierreMin) {
    return horaActualMin >= aperturaMin && horaActualMin < cierreMin;
  }

  // Caso cruza medianoche: 19:00 - 02:00
  return horaActualMin >= aperturaMin || horaActualMin < cierreMin;
}

function obtenerAhoraCanarias() {
  const now = new Date();

  const weekdayEs = new Intl.DateTimeFormat('es-ES', {
    timeZone: TZ,
    weekday: 'long',
  }).format(now);

  const timeParts = new Intl.DateTimeFormat('en-GB', {
    timeZone: TZ,
    hour: '2-digit',
    minute: '2-digit',
    second: '2-digit',
    hour12: false,
  }).formatToParts(now);

  const mapa = {};
  for (const p of timeParts) {
    mapa[p.type] = p.value;
  }

  const hora = Number(mapa.hour);
  const minuto = Number(mapa.minute);

  return {
    diaNombre: capitalizar(weekdayEs),
    diaNormalizado: normalizar(weekdayEs),
    horaActualMin: hora * 60 + minuto,
  };
}

function proximaApertura(diaActualIndex, horaActualMin) {
  for (let offset = 0; offset <= 7; offset++) {
    const idx = (diaActualIndex + offset) % 7;
    const diaBuscado = diasSemana[idx];
    const config = buscarDia(diaBuscado);

    if (!estaDisponible(config)) continue;

    const ventanas = [
      { hora: config.apertura1, min: toMinutes(config.apertura1) },
      { hora: config.apertura2, min: toMinutes(config.apertura2) },
    ]
      .filter(v => v.min !== null)
      .sort((a, b) => a.min - b.min);

    if (offset === 0) {
      const siguienteHoy = ventanas.find(v => v.min > horaActualMin);
      if (siguienteHoy) {
        return {
          dia: config.dia || capitalizar(diaBuscado),
          hora: formatearHora(siguienteHoy.hora),
          esHoy: true,
        };
      }
    } else {
      if (ventanas.length > 0) {
        return {
          dia: config.dia || capitalizar(diaBuscado),
          hora: formatearHora(ventanas[0].hora),
          esHoy: false,
        };
      }
    }
  }

  return null;
}

function mensajeProximaApertura(prox) {
  if (!prox) return 'No estaremos disponibles en los próximos días.';
  if (prox.esHoy) return `Abrimos hoy a las ${prox.hora}.`;
  return `La próxima apertura es el ${prox.dia} a las ${prox.hora}.`;
}

function getNodeValue(nodeName, key, fallback = null) {
  try {
    const data = $(nodeName).first().json;
    return data?.[key] ?? fallback;
  } catch {
    return fallback;
  }
}

// ================================
// 3) Datos actuales en Canarias
// ================================
const ahora = obtenerAhoraCanarias();
const diaActual = ahora.diaNombre;
const diaActualNorm = ahora.diaNormalizado;
const horaActualMin = ahora.horaActualMin;
const diaActualIndex = diasSemana.indexOf(diaActualNorm);
const diaAyerIndex = (diaActualIndex + 6) % 7;

// ================================
// 4) Campos que necesita el agente
// ================================
const conversation_id = getNodeValue('Input Agente1', 'conversation_id');
const input = getNodeValue('Input Agente1', 'input');
const contexto = getNodeValue('Input Agente1', 'contexto');
const telefono = getNodeValue('Variables', 'telefono');

// ================================
// 5) Buscar configuraciones
// ================================
const configHoy = buscarDia(diaActualNorm);
const configAyer = buscarDia(diasSemana[diaAyerIndex]);

// ================================
// 6) Evaluar abierto/cerrado
// ================================
let abierto = false;

// 6.1 Revisar horario de hoy
if (estaDisponible(configHoy)) {
  const apertura1 = toMinutes(configHoy.apertura1);
  const cierre1 = toMinutes(configHoy.cierre1);
  const apertura2 = toMinutes(configHoy.apertura2);
  const cierre2 = toMinutes(configHoy.cierre2);

  if (estaDentroDelIntervalo(horaActualMin, apertura1, cierre1)) {
    abierto = true;
  }

  if (!abierto && estaDentroDelIntervalo(horaActualMin, apertura2, cierre2)) {
    abierto = true;
  }
}

// 6.2 Revisar si ayer tenía un turno que cruza medianoche
if (!abierto && estaDisponible(configAyer)) {
  const apertura1Ayer = toMinutes(configAyer.apertura1);
  const cierre1Ayer = toMinutes(configAyer.cierre1);
  const apertura2Ayer = toMinutes(configAyer.apertura2);
  const cierre2Ayer = toMinutes(configAyer.cierre2);

  if (
    intervaloCruzaMedianoche(apertura1Ayer, cierre1Ayer) &&
    horaActualMin < cierre1Ayer
  ) {
    abierto = true;
  }

  if (
    !abierto &&
    intervaloCruzaMedianoche(apertura2Ayer, cierre2Ayer) &&
    horaActualMin < cierre2Ayer
  ) {
    abierto = true;
  }
}

// ================================
// 7) Respuesta si está abierto
// ================================
if (abierto) {
  return [{
    json: {
      estado: 'Abierto',
      tipo: null,
      mensaje: 'Estamos abiertos y listos para atenderte.',
      conversation_id,
      input,
      contexto,
      telefono,
      cliente_nombre: getNodeValue('Input Agente1','cliente_nombre',''),
      direccion_frecuente: getNodeValue('Input Agente1','direccion_frecuente',''),
      usuario_id: getNodeValue('Input Agente1','usuario_id',null),
    }
  }];
}

// ================================
// 8) Si no existe horario para hoy
// ================================
if (!configHoy) {
  const prox = proximaApertura(diaActualIndex, horaActualMin);

  return [{
    json: {
      estado: 'Cerrado',
      tipo: 'Dia',
      mensaje: `Hoy ${diaActual} el local está cerrado. ${mensajeProximaApertura(prox)}`,
      conversation_id,
      input,
      contexto,
      telefono,
      cliente_nombre: getNodeValue('Input Agente1','cliente_nombre',''),
      direccion_frecuente: getNodeValue('Input Agente1','direccion_frecuente',''),
      usuario_id: getNodeValue('Input Agente1','usuario_id',null),
    }
  }];
}

// ================================
// 9) Si hoy no está disponible
// ================================
if (!estaDisponible(configHoy)) {
  const prox = proximaApertura(diaActualIndex, horaActualMin);

  return [{
    json: {
      estado: 'Cerrado',
      tipo: 'Dia',
      mensaje: `Hoy ${diaActual} no atendemos. ${mensajeProximaApertura(prox)}`,
      conversation_id,
      input,
      contexto,
      telefono,
      cliente_nombre: getNodeValue('Input Agente1','cliente_nombre',''),
      direccion_frecuente: getNodeValue('Input Agente1','direccion_frecuente',''),
      usuario_id: getNodeValue('Input Agente1','usuario_id',null),
    }
  }];
}

// ================================
// 10) Cerrado por horario
// ================================
const prox = proximaApertura(diaActualIndex, horaActualMin);

const bloquesHorario = [];
if (configHoy.apertura1 && configHoy.cierre1) {
  bloquesHorario.push(`${formatearHora(configHoy.apertura1)} - ${formatearHora(configHoy.cierre1)}`);
}
if (configHoy.apertura2 && configHoy.cierre2) {
  bloquesHorario.push(`${formatearHora(configHoy.apertura2)} - ${formatearHora(configHoy.cierre2)}`);
}
const textoHorario = bloquesHorario.length > 0
  ? bloquesHorario.join(' y ')
  : 'sin horario definido';

return [{
  json: {
    estado: 'Cerrado',
    tipo: 'Hora',
    mensaje: `En este momento estamos cerrados. Nuestro horario hoy ${diaActual} es ${textoHorario}. ${mensajeProximaApertura(prox)}`,
    conversation_id,
    input,
    contexto,
    telefono,
  }
}];

let texto = String(items[0].json.output || '').trim();
const outputOriginal = texto; 

texto = texto
  .replace(/^["']|["']$/g, '')
  .replace(/[¿¡]/g, '')
  .replace(/\r/g, '')
  .replace(/\n{2,}/g, '\n')
  .replace(/[ \t]+/g, ' ')
  .trim();

return [{
  json: {
    mensaje: texto,
    outputOriginal
  }
}];

const contextoActual = $json.contexto || '';
const sessionIdDb = $json.session_id || null;
const sessionStartedDb = $json.session_started_at || null;
const SESSION_TIMEOUT_MINUTES = 30;

function generarUUID() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c) {
    const r = Math.random() * 16 | 0;
    const v = c === 'x' ? r : (r & 0x3 | 0x8);
    return v.toString(16);
  });
}

let sessionId = sessionIdDb;
let sessionStarted = sessionStartedDb ? new Date(sessionStartedDb) : null;

if (!sessionId) {
  const match = contextoActual.match(/SESSION_ID:\s*([a-f0-9-]+)/i);
  if (match) sessionId = match[1];
}
if (!sessionStarted) {
  const match = contextoActual.match(/SESSION_STARTED:\s*([0-9T:\-\.Z]+)/i);
  if (match) {
    const parsed = new Date(match[1].trim());
    if (!isNaN(parsed.getTime())) sessionStarted = parsed;
  }
}

const ahora = new Date();
let nuevaSesion = false;
let razonNuevaSesion = 'activa';

if (!sessionId || !sessionStarted || isNaN(sessionStarted.getTime())) {
  nuevaSesion = true;
  razonNuevaSesion = !sessionId ? 'primera_vez' : 'sin_timestamp';
} else {
  const minutosPasados = (ahora - sessionStarted) / 1000 / 60;
  if (minutosPasados > SESSION_TIMEOUT_MINUTES) {
    nuevaSesion = true;
    razonNuevaSesion = 'timeout';
  }
}

if (nuevaSesion) {
  sessionId = generarUUID();
  sessionStarted = ahora;
}

return [{
  json: {
    ...$json,
    session_id: sessionId,
    session_started_at: sessionStarted.toISOString(),
    session_is_new: nuevaSesion,
    session_razon: razonNuevaSesion,
    session_timeout_minutes: SESSION_TIMEOUT_MINUTES,
    session_timestamp_now: ahora.toISOString()
  }
}];
